{
  "fileEdits": [
    {
      "path": "page/interactives/dot-alignment.yaml",
      "find": "rounded to whole numbers",
      "replace": "rounded to one decimal place"
    },
    {
      "path": "page/interactives/dot-alignment.yaml",
      "find": "At any moment the best-aligned candidate's bar visibly leads.",
      "replace": "At any moment the best-aligned candidate's bar visibly leads while all lengths are equal; when c1 is stretched, its bar can climb past a better-aligned candidate's, and that ranking flip must read from a still frame."
    },
    {
      "path": "page/interactives/dot-alignment.yaml",
      "find": "feels the score\n    climb on length alone: magnitude cheats the meter that direction earns.",
      "replace": "feels the score\n    climb on length alone until poorly aligned c1 overtakes a better\n    aligned candidate: magnitude cheats the meter that direction earns."
    },
    {
      "path": "page/interactives/dot-alignment.yaml",
      "find": "    - id: length-cheat\n      description: >-\n        probe held at 90 degrees while c1 is stretched to 2.0; c1's score\n        climbs on length alone though its direction never improved, showing\n        length cheats the similarity read\n      drive:\n        - { do: set-slider, value: 90 }\n        - { do: set-control, control: length-c1, value: 2.0 }",
      "replace": "    - id: length-cheat\n      description: >-\n        probe held at 70 degrees, pointing straight along c2 so c2 honestly\n        leads the reading; then c1 is stretched to 2.0 until its score\n        climbs past c2's on length alone though c1's direction never\n        improved, a visible ranking flip showing length cheats the\n        similarity read\n      drive:\n        - { do: set-slider, value: 70 }\n        - { do: set-control, control: length-c1, value: 2.0 }"
    }
  ],
  "summary": "Set the dot-product readouts to one decimal place and re-drove the length-cheat state to probe 70 (on c2) so stretching c1 overtakes the honestly-aligned c2 as a visible ranking flip."
}

